import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import * as actions from '../../redux/actions';
import {
  Box,
  Container,
  Paper,
  TextField,
  Button,
  Typography,
  ToggleButtonGroup,
  ToggleButton,
  Avatar,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  Divider,
  Badge,
  Stack,
  Chip,
  IconButton,
  useMediaQuery,
  useTheme,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Grid,
} from '@mui/material';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction';
import SearchIcon from '@mui/icons-material/Search';
import CalendarMonthIcon from '@mui/icons-material/CalendarMonth';
import ViewListIcon from '@mui/icons-material/ViewList';
import PersonIcon from '@mui/icons-material/Person';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import PlaceIcon from '@mui/icons-material/Place';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import ClearIcon from '@mui/icons-material/Clear';
import dayjs from 'dayjs';
import 'dayjs/locale/th';
import relativeTime from 'dayjs/plugin/relativeTime';
import _ from 'lodash';

dayjs.locale('th');
dayjs.extend(relativeTime);

export default function ManpowerCheckTimeStamp() {
  const dispatch = useDispatch();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

  const timestamp = useSelector((state) => state.timestamp);

  const [searchName, setSearchName] = useState('');
  const [searchEmployeeId, setSearchEmployeeId] = useState('');
  const [viewMode, setViewMode] = useState('calendar');
  const [dateStart, setDateStart] = useState(
    dayjs().startOf('month').toISOString(),
  );
  const [dateEnd, setDateEnd] = useState(dayjs().endOf('month').toISOString());
  const [openEventModal, setOpenEventModal] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null);

  const handleSearch = () => {
    if (_.isEmpty(searchName) && _.isEmpty(searchEmployeeId))
      return alert('กรุณากรอกข้อมูลเพื่อค้นหา');
    dispatch(
      actions.timestampAll({
        name: searchName,
        employeekey: searchEmployeeId,
      }),
    );
  };

  const handleClearSearch = () => {
    setSearchName('');
    setSearchEmployeeId('');
    dispatch(
      actions.timestampAll({
        name: '',
        status_checkIn: true,
        dateStart,
        dateEnd,
        employeekey: '',
      }),
    );
  };

  const handleViewModeChange = (event, newMode) => {
    if (newMode !== null) {
      setViewMode(newMode);
    }
  };

  const calendarEvents = _.map(timestamp?.rows, (item) => ({
    id: item._id,
    title: `${item?.employee_firstname} ${item?.employee_lastname}`,
    date: dayjs(item?.createdAt).format('YYYY-MM-DD'),
    backgroundColor: item?.out_of_location ? '#dc3545' : '#28a745',
    borderColor: item?.out_of_location ? '#dc3545' : '#28a745',
    extendedProps: {
      ...item,
    },
  }));

  const renderSearchSection = () => (
    <Paper
      elevation={0}
      sx={{
        p: { xs: 2.5, sm: 3 },
        borderRadius: 4,
        background: 'linear-gradient(135deg, #ffffff 0%, #f8f9ff 100%)',
        boxShadow: '0 8px 24px rgba(102, 126, 234, 0.12)',
        border: '1px solid rgba(102, 126, 234, 0.1)',
        mb: 3,
      }}
    >
      <Typography
        variant="h5"
        sx={{
          fontWeight: 700,

          backgroundClip: 'text',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          mb: 2,
          display: 'flex',
          alignItems: 'center',
          gap: 1,
        }}
      >
        <SearchIcon />
        ค้นหารายการลงเวลา
      </Typography>

      <Stack spacing={2}>
        <Box sx={{ display: 'flex', gap: 1.5, flexWrap: 'wrap' }}>
          <TextField
            label="ค้นหาชื่อพนักงาน"
            variant="outlined"
            value={searchName}
            required
            onChange={(e) => setSearchName(e.target.value)}
            onKeyPress={(e) => {
              if (e.key === 'Enter') {
                handleSearch();
              }
            }}
            sx={{
              flex: 1,
              minWidth: 200,
              '& .MuiOutlinedInput-root': {
                borderRadius: 2.5,
                '&:hover fieldset': {
                  borderColor: '#667eea',
                },
                '&.Mui-focused fieldset': {
                  borderColor: '#667eea',
                },
              },
            }}
            InputProps={{
              endAdornment: searchName && (
                <IconButton size="small" onClick={handleClearSearch}>
                  <ClearIcon fontSize="small" />
                </IconButton>
              ),
            }}
          />

          {/* <TextField
            label="เลขรหัสพนักงาน"
            variant="outlined"
            value={searchEmployeeId}
            onChange={(e) => setSearchEmployeeId(e.target.value)}
            onKeyPress={(e) => {
              if (e.key === 'Enter') {
                handleSearch();
              }
            }}
            sx={{
              flex: 1,
              minWidth: 200,
              '& .MuiOutlinedInput-root': {
                borderRadius: 2.5,
                '&:hover fieldset': {
                  borderColor: '#667eea',
                },
                '&.Mui-focused fieldset': {
                  borderColor: '#667eea',
                },
              },
            }}
          /> */}

          <Button
            variant="contained"
            startIcon={<SearchIcon />}
            onClick={handleSearch}
            sx={{
              borderRadius: 2.5,
              px: 4,
              py: 1.5,
              fontWeight: 600,
              textTransform: 'none',
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              boxShadow: '0 4px 12px rgba(102, 126, 234, 0.3)',
              '&:hover': {
                background: 'linear-gradient(135deg, #764ba2 0%, #667eea 100%)',
                boxShadow: '0 6px 16px rgba(102, 126, 234, 0.4)',
              },
            }}
          >
            ค้นหา
          </Button>
        </Box>

        <Box
          sx={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            flexWrap: 'wrap',
            gap: 2,
          }}
        >
          <Chip
            icon={<PersonIcon />}
            label={`พบทั้งหมด ${timestamp?.rows?.length || 0} รายการ`}
            sx={{
              fontWeight: 600,
              fontSize: '0.95rem',
              py: 2.5,
              px: 1,
              background: 'linear-gradient(135deg, #e3f2fd 0%, #f3e5f5 100%)',
              border: '1px solid rgba(102, 126, 234, 0.2)',
            }}
          />

          <ToggleButtonGroup
            value={viewMode}
            exclusive
            onChange={handleViewModeChange}
            sx={{
              '& .MuiToggleButton-root': {
                borderRadius: 2,
                px: 3,
                py: 1,
                fontWeight: 600,
                textTransform: 'none',
                border: '1px solid rgba(102, 126, 234, 0.3)',
                '&.Mui-selected': {
                  background:
                    'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  '&:hover': {
                    background:
                      'linear-gradient(135deg, #764ba2 0%, #667eea 100%)',
                  },
                },
              },
            }}
          >
            <ToggleButton value="calendar">
              <CalendarMonthIcon sx={{ mr: 1 }} />
              ปฏิทิน
            </ToggleButton>
            <ToggleButton value="list">
              <ViewListIcon sx={{ mr: 1 }} />
              รายการ
            </ToggleButton>
          </ToggleButtonGroup>
        </Box>
      </Stack>
    </Paper>
  );

  const renderCalendarView = () => (
    <Paper
      elevation={0}
      sx={{
        p: { xs: 2, sm: 3 },
        borderRadius: 4,
        background: 'linear-gradient(135deg, #ffffff 0%, #f8f9ff 100%)',
        boxShadow: '0 8px 24px rgba(102, 126, 234, 0.12)',
        border: '1px solid rgba(102, 126, 234, 0.1)',
      }}
    >
      <FullCalendar
        plugins={[dayGridPlugin, interactionPlugin]}
        initialView="dayGridMonth"
        locale="th"
        events={calendarEvents}
        height="auto"
        headerToolbar={{
          left: 'prev,next today',
          center: 'title',
          right: 'dayGridMonth,dayGridWeek',
        }}
        eventClick={(info) => {
          setSelectedEvent(info.event.extendedProps);
          setOpenEventModal(true);
        }}
        dayCellClassNames="custom-day-cell"
        eventClassNames="custom-event"
      />
    </Paper>
  );

  const renderListView = () => (
    <Paper
      elevation={0}
      sx={{
        borderRadius: 4,
        background: 'linear-gradient(135deg, #ffffff 0%, #f8f9ff 100%)',
        boxShadow: '0 8px 24px rgba(102, 126, 234, 0.12)',
        border: '1px solid rgba(102, 126, 234, 0.1)',
        overflow: 'hidden',
      }}
    >
      {_.isEmpty(timestamp?.rows) ? (
        <Box
          sx={{
            p: 6,
            textAlign: 'center',
            color: 'text.secondary',
          }}
        >
          <SearchIcon sx={{ fontSize: 64, opacity: 0.3, mb: 2 }} />
          <Typography variant="h6">ไม่พบรายการลงเวลา</Typography>
          <Typography variant="body2">
            ลองค้นหาด้วยชื่อพนักงานหรือปรับช่วงเวลา
          </Typography>
        </Box>
      ) : (
        <List sx={{ py: 0 }}>
          {_.map(timestamp?.rows, (item, index) => (
            <React.Fragment key={item._id || index}>
              <ListItem
                sx={{
                  py: 2.5,
                  px: { xs: 2, sm: 3 },
                  '&:hover': {
                    bgcolor: 'rgba(102, 126, 234, 0.05)',
                  },
                }}
              >
                <ListItemAvatar>
                  <Badge
                    overlap="circular"
                    anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
                    badgeContent={
                      <CheckCircleIcon
                        sx={{
                          color: '#28a745',
                          fontSize: 20,
                          bgcolor: 'white',
                          borderRadius: '50%',
                        }}
                      />
                    }
                  >
                    <Avatar
                      src={item?.image}
                      sx={{
                        width: isMobile ? 48 : 56,
                        height: isMobile ? 48 : 56,
                        border: '2px solid #667eea',
                      }}
                    >
                      <PersonIcon />
                    </Avatar>
                  </Badge>
                </ListItemAvatar>

                <ListItemText
                  primary={
                    <Box>
                      <Typography variant="subtitle1" fontWeight="bold">
                        {item?.employee_firstname} {item?.employee_lastname}
                      </Typography>
                      <Box
                        display="flex"
                        alignItems="center"
                        gap={1}
                        mt={0.5}
                        flexWrap="wrap"
                      >
                        <Chip
                          icon={<AccessTimeIcon fontSize="small" />}
                          label={dayjs(item?.createdAt).format(
                            'DD/MM/YYYY HH:mm น.',
                          )}
                          size="small"
                          sx={{
                            bgcolor: '#e3f2fd',
                            fontWeight: 600,
                          }}
                        />
                        <Typography variant="caption" color="text.secondary">
                          ({dayjs(item?.createdAt).fromNow()})
                        </Typography>
                      </Box>
                    </Box>
                  }
                  secondary={
                    <Box sx={{ mt: 1.5 }}>
                      <Stack spacing={1}>
                        {item?.project_in?.name && (
                          <Box display="flex" alignItems="center" gap={0.5}>
                            <PlaceIcon fontSize="small" color="primary" />
                            <Typography variant="body2">
                              โครงการ: {item?.project_in?.name}
                            </Typography>
                          </Box>
                        )}

                        {(item?.otRequests || item?.salary_extra?.hr > 0) && (
                          <Box display="flex" alignItems="center" gap={0.5}>
                            <AccessTimeIcon
                              fontSize="small"
                              sx={{ color: '#f57c00' }}
                            />
                            <Typography
                              variant="body2"
                              sx={{ color: '#e65100', fontWeight: 500 }}
                            >
                              OT:{' '}
                              {item?.otRequests
                                ? `${
                                    item.otRequests.total_hours
                                  } ชม. (${item.otRequests.total_price?.toFixed(
                                    2,
                                  )} ฿)`
                                : `${item.salary_extra.hr} ชม.`}
                            </Typography>
                          </Box>
                        )}

                        {item?.out_of_location && (
                          <Box display="flex" alignItems="center" gap={0.5}>
                            <LocationOnIcon fontSize="small" color="error" />
                            <Typography variant="body2" color="error">
                              อยู่นอกพื้นที่โครงการ
                            </Typography>
                          </Box>
                        )}

                        {item?.employeeType?.name && (
                          <Typography variant="caption" color="text.secondary">
                            ประเภท: {item?.employeeType?.name}
                          </Typography>
                        )}
                      </Stack>
                    </Box>
                  }
                />
              </ListItem>

              {index < timestamp?.rows?.length - 1 && (
                <Divider sx={{ borderColor: 'rgba(102, 126, 234, 0.1)' }} />
              )}
            </React.Fragment>
          ))}
        </List>
      )}
    </Paper>
  );

  const renderEventModal = () => (
    <Dialog
      open={openEventModal}
      onClose={() => setOpenEventModal(false)}
      fullWidth
      fullScreen={isMobile}
      maxWidth="sm"
      PaperProps={{
        sx: { borderRadius: isMobile ? 0 : 3 },
      }}
    >
      <DialogTitle
        sx={{
          borderBottom: 1,
          borderColor: 'divider',
          fontWeight: 'bold',
          fontSize: '1.25rem',
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          color: 'white',
        }}
      >
        รายละเอียดการลงเวลา
      </DialogTitle>
      <DialogContent sx={{ pt: 3 }}>
        {selectedEvent && (
          <Stack spacing={3} sx={{ mt: 2 }}>
            <Box display="flex" alignItems="center" gap={2}>
              <Avatar
                src={selectedEvent.employee?.image_profile}
                sx={{ width: 72, height: 72, border: '3px solid #f0f2f5' }}
              />
              <Box>
                <Typography variant="h6" fontWeight="bold">
                  {selectedEvent.employee_firstname}{' '}
                  {selectedEvent.employee_lastname}
                </Typography>

                <Typography
                  variant="body2"
                  color="text.secondary"
                  sx={{ mt: 0.5 }}
                >
                  {selectedEvent.employee?.role?.name || 'ตำแหน่งทั่วไป'}
                </Typography>
              </Box>
            </Box>

            <Divider />

            <Grid container spacing={2}>
              <Grid item xs={6}>
                <Paper
                  variant="outlined"
                  sx={{ p: 2, borderRadius: 2, bgcolor: '#f8f9fa' }}
                >
                  <Typography
                    variant="caption"
                    color="text.secondary"
                    display="block"
                    mb={0.5}
                  >
                    เวลาเข้างาน
                  </Typography>
                  <Stack direction="row" alignItems="center" gap={1}>
                    <AccessTimeIcon color="success" fontSize="small" />
                    <Typography variant="body1" fontWeight="600">
                      {selectedEvent.checkIn
                        ? dayjs(selectedEvent.checkIn).format('HH:mm')
                        : '-'}
                    </Typography>
                  </Stack>
                  <Typography variant="caption" color="text.secondary">
                    {selectedEvent.checkIn
                      ? dayjs(selectedEvent.checkIn).format('DD/MM/YYYY')
                      : ''}
                  </Typography>
                </Paper>
              </Grid>
              <Grid item xs={6}>
                <Paper
                  variant="outlined"
                  sx={{ p: 2, borderRadius: 2, bgcolor: '#f8f9fa' }}
                >
                  <Typography
                    variant="caption"
                    color="text.secondary"
                    display="block"
                    mb={0.5}
                  >
                    เวลาออกงาน
                  </Typography>
                  <Stack direction="row" alignItems="center" gap={1}>
                    <AccessTimeIcon color="error" fontSize="small" />
                    <Typography variant="body1" fontWeight="600">
                      {selectedEvent.checkOut
                        ? dayjs(selectedEvent.checkOut).format('HH:mm')
                        : '-'}
                    </Typography>
                  </Stack>
                  <Typography variant="caption" color="text.secondary">
                    {selectedEvent.checkOut
                      ? dayjs(selectedEvent.checkOut).format('DD/MM/YYYY')
                      : ''}
                  </Typography>
                </Paper>
              </Grid>

              <Grid item xs={12}>
                <Box
                  sx={{ p: 2, borderRadius: 2, border: '1px dashed #bdbdbd' }}
                >
                  <Typography
                    variant="subtitle2"
                    color="text.secondary"
                    gutterBottom
                  >
                    รายละเอียด OT
                  </Typography>
                  {selectedEvent.otRequests ? (
                    <Grid container spacing={2}>
                      <Grid item xs={6}>
                        <Typography variant="caption" color="text.secondary">
                          เวลาเข้า (OT)
                        </Typography>
                        <Typography variant="body2" fontWeight="600">
                          {dayjs(selectedEvent.otRequests.startTime).format(
                            'HH:mm',
                          )}
                        </Typography>
                      </Grid>
                      <Grid item xs={6}>
                        <Typography variant="caption" color="text.secondary">
                          เวลาออก (OT)
                        </Typography>
                        <Typography variant="body2" fontWeight="600">
                          {dayjs(selectedEvent.otRequests.endTime).format(
                            'HH:mm',
                          )}
                        </Typography>
                      </Grid>
                      <Grid item xs={4}>
                        <Typography variant="caption" color="text.secondary">
                          จำนวนชั่วโมง
                        </Typography>
                        <Typography variant="body2" fontWeight="600">
                          {selectedEvent.otRequests.total_hours} ชม.
                        </Typography>
                      </Grid>
                      <Grid item xs={4}>
                        <Typography variant="caption" color="text.secondary">
                          เรท
                        </Typography>
                        <Typography variant="body2" fontWeight="600">
                          x{selectedEvent.otRequests.rate}
                        </Typography>
                      </Grid>
                      <Grid item xs={4}>
                        <Typography variant="caption" color="text.secondary">
                          จำนวนเงิน
                        </Typography>
                        <Typography
                          variant="body2"
                          fontWeight="600"
                          color="primary"
                        >
                          {selectedEvent.otRequests.total_price?.toFixed(2)} ฿
                        </Typography>
                      </Grid>
                    </Grid>
                  ) : (
                    <Typography variant="body1">
                      {selectedEvent.salary_extra?.hr
                        ? `${selectedEvent.salary_extra.hr} ชั่วโมง`
                        : 'ไม่มีรายการ OT'}
                    </Typography>
                  )}
                </Box>
              </Grid>

              <Grid item xs={12}>
                <Typography variant="subtitle2" color="text.secondary">
                  โครงการ
                </Typography>
                <Box display="flex" alignItems="center" gap={1} mt={0.5}>
                  <PlaceIcon color="action" />
                  <Typography variant="body1">
                    {selectedEvent.project_in?.name || '-'}
                  </Typography>
                </Box>
              </Grid>

              {selectedEvent.note && (
                <Grid item xs={12}>
                  <Typography variant="subtitle2" color="text.secondary">
                    หมายเหตุ
                  </Typography>
                  <Typography
                    variant="body2"
                    sx={{ bgcolor: '#fff3e0', p: 1, borderRadius: 1 }}
                  >
                    {selectedEvent.note}
                  </Typography>
                </Grid>
              )}
            </Grid>
          </Stack>
        )}
      </DialogContent>
      <DialogActions sx={{ p: 2.5 }}>
        <Button
          onClick={() => setOpenEventModal(false)}
          variant="contained"
          color="secondary"
        >
          ปิดหน้าต่าง
        </Button>
      </DialogActions>
    </Dialog>
  );

  return (
    <Box
      sx={{
        minHeight: '100vh',

        py: { xs: 2, sm: 4 },
        position: 'relative',
        '&::before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background:
            'radial-gradient(circle at 20% 50%, rgba(255,255,255,0.1) 0%, transparent 50%)',
          pointerEvents: 'none',
        },
      }}
    >
      <Container maxWidth="lg" sx={{ position: 'relative', zIndex: 1 }}>
        {renderSearchSection()}
        {viewMode === 'calendar' ? renderCalendarView() : renderListView()}
        {renderEventModal()}
      </Container>
    </Box>
  );
}
