import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useHistory } from 'react-router';
import * as actions from '../../redux/actions';
import { ViewTitle } from 'components/ViewTitle';

import {
  Box,
  Button,
  Modal,
  Typography,
  Stack,
  Paper,
  Grid,
  Divider,
  Chip,
  useTheme,
  alpha,
  Card,
  Container,
  Tooltip,
  IconButton,
  Backdrop,
  Fade,
} from '@mui/material';
import { useForm, Controller } from 'react-hook-form';
import ExpensesApplyForm from '../../components/Forms/ExpensesApplyForm';
import { ExpensesTableApplove } from '../../components/Table';
import ExpensesHrApplyForm from '../../components/Forms/ExpensesHrApplyForm';
import AddpayoutForm from '../../components/Forms/AddpayoutForm';
import { expensesReport } from 'components/PDF';
import FilterFinanceExpenses from '../../components/Card/FilterFinanceExpenses';
import FinanceExcel from '../../components/Excel/FinanceExcel';
import { ButtonGroup } from 'components/Button';
import dayjs from 'dayjs';

// Icons
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import ReceiptLongIcon from '@mui/icons-material/ReceiptLong';
import CurrencyExchangeIcon from '@mui/icons-material/CurrencyExchange';
import EventNoteIcon from '@mui/icons-material/EventNote';
import AddIcon from '@mui/icons-material/Add';
import PrintIcon from '@mui/icons-material/Print';
import GetAppIcon from '@mui/icons-material/GetApp';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PersonIcon from '@mui/icons-material/Person';
import CloseIcon from '@mui/icons-material/Close';
import { CustomerForm } from 'components/Forms';
import DatePickerCard from 'components/Card/DatePickerCard';

const style = {
  position: 'absolute',
  top: '50%',
  left: '50%',
  transform: 'translate(-50%, -50%)',
  width: { xs: '90%', sm: '80%', md: '60%' },
  bgcolor: 'background.paper',
  borderRadius: 2,
  boxShadow: 24,
  p: { xs: 2, sm: 4 },
  maxHeight: '90vh',
  overflow: 'auto',
};

function ExpensesList({ title, subtitle }) {
  const dispatch = useDispatch();
  const history = useHistory();
  const theme = useTheme();

  const expenses = useSelector((state) => state.expenses);
  const projects = useSelector((state) => state.project);
  const customer = useSelector((state) => state.customer);
  const customerType = useSelector((state) => state.customerType);
  const me = useSelector((state) => state.me);
  const info = useSelector((state) => state.info);

  const [page, setPage] = useState(1);
  const [size, setSize] = useState(20);
  const [open, setOpen] = useState(false);
  const [date, setDate] = useState(new Date());
  const [paidType, setPaidType] = useState('TRANSFER');
  const [projectSelect, setProjectSelect] = useState('');
  const [budgetSelect, setBudgetSelect] = useState('');
  const [openPay, setOpenPay] = useState(false);
  const [datePay, setDatePay] = useState(new Date());
  const [exSelect, setExSelect] = useState('');
  const [bank, setBank] = useState();
  const [findProject, setFindProject] = useState('');
  const [search, setSearch] = useState('');
  const [dateStart, setDateStart] = useState([new Date(), new Date()]);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [openCustomerModal, setOpenCustomerModal] = useState(false);
  const [customerSelect, setCustomerSelect] = useState('');
  const [selectedRows, setSelectedRows] = useState([]);
  const [openPrepareModal, setOpenPrepareModal] = useState(false);

  const {
    control,
    formState: { errors },
    handleSubmit,
    reset,
    setValue,
  } = useForm();

  const {
    control: customerControl,
    formState: { errors: customerErrors },
    handleSubmit: handleCustomerSubmit,
    reset: resetCustomer,
    setValue: setCustomerValue,
  } = useForm();

  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);

  const handleOpenCustomerModal = () => setOpenCustomerModal(true);
  const handleCloseCustomerModal = () => {
    setOpenCustomerModal(false);
    resetCustomer();
  };

  const handleOpenPrepareModal = () => setOpenPrepareModal(true);
  const handleClosePrepareModal = () => setOpenPrepareModal(false);

  const handleExport = () => {
    const { exportToExcel } = FinanceExcel({
      data: expenses?.rows || [],
      fileName: 'expenses_report',
    });
    exportToExcel();
  };

  const handleOpenPay = (e) => {
    setOpenPay(true);
    setExSelect(e);
    setValue('price', e?.price);
  };

  const handleClosePay = () => setOpenPay(false);

  const fetchExpenses = async () => {
    setIsRefreshing(true);
    await dispatch(
      actions.expensesAll({
        page,
        size,
        search,
        findProject: findProject?._id,
        dateStart: dayjs(dateStart[0]).startOf('day').toDate(),
        dateEnd: dayjs(dateStart[1]).endOf('day').toDate(),
      }),
    );
    setIsRefreshing(false);
  };

  useEffect(() => {
    fetchExpenses();

    return () => {};
  }, [page, size, search, findProject, dateStart]);

  useEffect(() => {
    dispatch(actions.projectAll({}));
    dispatch(actions.customerAll({}));
    dispatch(actions.meGet());
    dispatch(actions.getInformation({}));
    dispatch(actions.customerAll({}));
    dispatch(actions.customerTypeAll({}));
    return () => {};
  }, []);

  useEffect(() => {
    dispatch(actions.budgetAll({ project_id: projectSelect?.id }));
    return () => {};
  }, [projectSelect]);

  const filter = expenses?.rows;

  const handleDelete = async (id) => {
    const confirm = window.confirm('ลบข้อมูล');
    if (confirm) {
      try {
        await dispatch(actions.expensesPut(id, { status: 'CANCEL' }));
        fetchExpenses();
      } catch (error) {}
    }
  };

  const handleEdit = (id) => {
    history.push(`/finance/expenses/edit/${id}`);
  };

  const handleDetail = (id) => {
    history.push(`/finance/expenses/detail/${id}`);
  };

  const handleApprove = async (id) => {
    await dispatch(actions.expensesPut(id, { status: 'APPROVE' }));
    fetchExpenses();
  };

  const handleSuccess = async (id) => {
    await dispatch(actions.expensesPut(id, { status: 'SUCCESS' }));
    fetchExpenses();
  };

  const handleReject = async (id) => {
    await dispatch(actions.expensesPut(id, { status: 'REJECT' }));
    fetchExpenses();
  };

  const handleBillPickup = async (id) => {
    await dispatch(actions.expensesPut(id, { bill_pickup: true }));
    fetchExpenses();
  };

  const handleReset = async (id) => {
    await dispatch(actions.expensesPut(id, { status: 'PENDING' }));
    fetchExpenses();
  };

  const handlePrint = async () => {
    expensesReport(expenses, info);
  };
  const onSubmitCustomer = async (data) => {
    try {
      data.bank = {
        bank_name: bank,
        account_name: data?.bank?.account_name,
        account_number: data?.bank?.account_number,
      };
      await dispatch(actions.customerCreate(data));
      await dispatch(actions.customerAll({}));
      handleCloseCustomerModal();
    } catch (error) {
      // handle error
    }
  };
  const handleAddCustomerFromPayment = () => {
    handleOpenCustomerModal();
  };

  const onSubmit = async (data) => {
    const confirm = window.confirm('บันทึกข้อมูล');
    if (confirm) {
      const dataSubmit = {
        ...data,
        paidType,
        date: dayjs(date).endOf('day').toISOString(),
        employee: me?.userData?._id,
        employee_data: me?.userData,
        budgetSelect: budgetSelect?._id,
        projectSelect,
        customer: customerSelect,
      };
      await dispatch(actions.expensesCreateWithOutNotify(dataSubmit));
      fetchExpenses();
      reset();
      handleClose();
    }
  };

  const onSubmitPay = async (data) => {
    const confirm = window.confirm('บันทึกข้อมูล');
    if (confirm) {
      const dataSubmit = {
        ...data,
        paidType,
        date: datePay,
        employee: me?.userData?._id,
        expenses: exSelect?.id,
        budget: exSelect?.budget?._id,
      };
      await dispatch(actions.payoutCreate(dataSubmit));
      await dispatch(actions.payoutAll({}));
      await dispatch(actions.expensesPut(exSelect?._id, { status: 'SUCCESS' }));
      fetchExpenses();
      reset();
      handleClosePay();
    }
  };

  const handleAddMultiPayment = async () => {
    const confirm = window.confirm('บันทึกข้อมูล');
    if (confirm) {
      await dispatch(actions.payoutCreate(selectedRows));
      await fetchExpenses();
      setSelectedRows([]);
    }
  };

  const handleCreatePayment = async () => {
    await dispatch(actions.paymentCreateWithExpenses({ date: date }));
    history.push('/finance/payment');
    handleClosePrepareModal();
  };

  const handleClick = () => {
    if (selectedIndex === 0) {
      handleOpen();
    }
    if (selectedIndex === 1) {
      handlePrint();
    }
    if (selectedIndex === 2) {
      handleExport();
    }
  };

  // คำนวณข้อมูลสรุป
  const filteredExpenses =
    filter?.filter(
      (item) => item.status !== 'REJECT' && item.status !== 'CANCEL',
    ) || [];

  const totalCount = filteredExpenses?.length || 0;
  const totalAmount =
    filteredExpenses?.reduce(
      (sum, expense) => sum + (expense?.price || 0),
      0,
    ) || 0;
  const pendingCount =
    filteredExpenses?.filter((item) => item.status === 'PENDING').length || 0;
  const pendingAmount =
    filteredExpenses
      ?.filter((item) => item.status === 'PENDING')
      .reduce((sum, expense) => sum + (expense?.price || 0), 0) || 0;
  const approvedCount =
    filteredExpenses?.filter((item) => item.status === 'APPROVE').length || 0;
  const approvedAmount =
    filteredExpenses
      ?.filter((item) => item.status === 'APPROVE')
      .reduce((sum, expense) => sum + (expense?.price || 0), 0) || 0;
  const successCount =
    filteredExpenses?.filter((item) => item.status === 'SUCCESS').length || 0;
  const successAmount =
    filteredExpenses
      ?.filter((item) => item.status === 'SUCCESS')
      .reduce((sum, expense) => sum + (expense?.price || 0), 0) || 0;

  const renderModalAddPayment = () => (
    <Modal
      open={openPay}
      onClose={handleClosePay}
      aria-labelledby="modal-payment-title"
      closeAfterTransition
    >
      <Fade in={openPay}>
        <Box sx={style}>
          <Typography variant="h6" component="h2" className="mb-4">
            เพิ่มข้อมูลการชำระเงิน
          </Typography>
          <Divider sx={{ mb: 2 }} />
          <form onSubmit={handleSubmit(onSubmitPay)}>
            <AddpayoutForm
              control={control}
              Controller={Controller}
              date={datePay}
              setDate={setDatePay}
              paidType={paidType}
            />
          </form>
        </Box>
      </Fade>
    </Modal>
  );

  const renderPrepareModal = () => (
    <Modal
      open={openPrepareModal}
      onClose={handleClosePrepareModal}
      aria-labelledby="modal-modal-title"
      aria-describedby="modal-modal-description"
    >
      <Box sx={style}>
        {/* Header */}
        <Box
          sx={{
            px: 3,
            py: 2.5,
            borderBottom: '1px solid',
            borderColor: 'divider',
            bgcolor: 'primary.main',
            color: 'white',
          }}
        >
          <Typography
            id="modal-modal-title"
            variant="h5"
            component="h2"
            sx={{ fontWeight: 600 }}
          >
            สร้างรายการจ่ายเงิน
          </Typography>
        </Box>

        {/* Content */}
        <Box
          id="modal-modal-description"
          sx={{
            p: 3,
            overflowY: 'auto',
            flex: 1,
          }}
        >
          <DatePickerCard setDate={setDate} date={date} />
        </Box>

        {/* Footer */}
        <Box
          sx={{
            px: 3,
            py: 2,
            borderTop: '1px solid',
            borderColor: 'divider',
            display: 'flex',
            justifyContent: 'flex-end',
            gap: 2,
            bgcolor: 'grey.50',
          }}
        >
          <Button
            variant="outlined"
            onClick={handleClosePrepareModal}
            sx={{ minWidth: 100 }}
          >
            ยกเลิก
          </Button>
          <Button
            variant="contained"
            color="primary"
            sx={{ minWidth: 100 }}
            onClick={handleCreatePayment}
          >
            สร้างรายการ
          </Button>
        </Box>
      </Box>
    </Modal>
  );

  const renderModal = () => (
    <Modal
      open={open}
      onClose={handleClose}
      aria-labelledby="modal-expense-title"
      closeAfterTransition
    >
      <Fade in={open}>
        <Box sx={style}>
          <Typography variant="h6" component="h2" className="mb-4">
            เพิ่มรายการเบิกจ่าย
          </Typography>
          <Divider sx={{ mb: 2 }} />
          <form onSubmit={handleSubmit(onSubmit)}>
            <ExpensesApplyForm
              control={control}
              Controller={Controller}
              date={date}
              setDate={setDate}
              paidType={paidType}
              setPaidType={setPaidType}
              projects={projects}
              setProjectSelect={setProjectSelect}
              projectSelect={projectSelect}
              setValue={setValue}
              budgetSelect={budgetSelect}
              setBudgetSelect={setBudgetSelect}
              bank={bank}
              setBank={setBank}
              customer={customer}
              onAddCustomer={handleAddCustomerFromPayment}
              setCustomerSelect={setCustomerSelect}
            />
          </form>
        </Box>
      </Fade>
    </Modal>
  );

  const renderSummary = () => (
    <Fade in={true} timeout={700}>
      <Paper
        elevation={0}
        sx={{
          mb: 3,
          borderRadius: 2,
          overflow: 'hidden',
          boxShadow: '0 2px 8px rgba(0,0,0,0.06)',
        }}
      >
        <Box
          sx={{
            px: 2,
            py: 1.5,
            background: `linear-gradient(135deg, ${theme.palette.primary.main}, ${theme.palette.primary.dark})`,
            color: 'white',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
          }}
        ></Box>

        <Box sx={{ px: 2, py: 1.5 }}>
          <Grid container spacing={2}>
            <Grid item xs={6} sm={3}>
              <Box
                sx={{
                  p: 1.5,
                  borderRadius: 1.5,
                  bgcolor: alpha(theme.palette.primary.light, 0.1),
                  border: `1px solid ${alpha(theme.palette.primary.main, 0.1)}`,
                }}
              >
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
                  <ReceiptLongIcon
                    fontSize="small"
                    sx={{ color: theme.palette.primary.main, mr: 0.5 }}
                  />
                  <Typography
                    variant="caption"
                    color="textSecondary"
                    sx={{ fontWeight: 500 }}
                  >
                    รายการทั้งหมด
                  </Typography>
                </Box>
                <Typography
                  variant="h6"
                  fontWeight="bold"
                  color="primary"
                  sx={{ lineHeight: 1.2 }}
                >
                  {totalCount.toLocaleString()} รายการ
                </Typography>
              </Box>
            </Grid>

            <Grid item xs={6} sm={3}>
              <Box
                sx={{
                  p: 1.5,
                  borderRadius: 1.5,
                  bgcolor: alpha(theme.palette.success.light, 0.1),
                  height: '100%',
                  border: `1px solid ${alpha(theme.palette.success.main, 0.1)}`,
                }}
              >
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
                  <CurrencyExchangeIcon
                    fontSize="small"
                    sx={{ color: theme.palette.success.main, mr: 0.5 }}
                  />
                  <Typography
                    variant="caption"
                    color="textSecondary"
                    sx={{ fontWeight: 500 }}
                  >
                    ยอดเงินทั้งหมด
                  </Typography>
                </Box>
                <Typography
                  variant="h6"
                  fontWeight="bold"
                  color="success.main"
                  sx={{ lineHeight: 1.2 }}
                >
                  ฿{totalAmount.toFixed(2).replace(/\d(?=(\d{3})+\.)/g, '$&,')}
                </Typography>
              </Box>
            </Grid>

            <Grid item xs={6} sm={3}>
              <Box
                sx={{
                  p: 1.5,
                  borderRadius: 1.5,
                  bgcolor: alpha(theme.palette.warning.light, 0.1),
                  height: '100%',
                  border: `1px solid ${alpha(theme.palette.warning.main, 0.1)}`,
                }}
              >
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
                  <TrendingUpIcon
                    fontSize="small"
                    sx={{ color: theme.palette.warning.main, mr: 0.5 }}
                  />
                  <Typography
                    variant="caption"
                    color="textSecondary"
                    sx={{ fontWeight: 500 }}
                  >
                    ยอดรออนุมัติ
                  </Typography>
                </Box>
                <Typography
                  variant="h6"
                  fontWeight="bold"
                  color="warning.main"
                  sx={{ lineHeight: 1.2 }}
                >
                  ฿
                  {pendingAmount.toFixed(2).replace(/\d(?=(\d{3})+\.)/g, '$&,')}
                </Typography>
              </Box>
            </Grid>

            <Grid item xs={6} sm={3}>
              <Box
                sx={{
                  p: 1.5,
                  borderRadius: 1.5,
                  bgcolor: alpha(theme.palette.info.light, 0.1),
                  height: '100%',
                  border: `1px solid ${alpha(theme.palette.info.main, 0.1)}`,
                }}
              >
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
                  <EventNoteIcon
                    fontSize="small"
                    sx={{ color: theme.palette.info.main, mr: 0.5 }}
                  />
                  <Typography
                    variant="caption"
                    color="textSecondary"
                    sx={{ fontWeight: 500 }}
                  >
                    วันที่แสดงผล
                  </Typography>
                </Box>
                <Typography
                  variant="body2"
                  fontWeight="medium"
                  sx={{ mb: 0.5 }}
                >
                  {dayjs(dateStart[0]).format('DD/MM/YY')} -{' '}
                  {dayjs(dateStart[1]).format('DD/MM/YY')}
                </Typography>
                {search && (
                  <Typography
                    noWrap
                    variant="caption"
                    color="textSecondary"
                    sx={{ display: 'block', fontSize: '0.65rem' }}
                  >
                    ค้นหา: "{search}"
                  </Typography>
                )}
              </Box>
            </Grid>
          </Grid>
        </Box>
      </Paper>
    </Fade>
  );

  const renderTable = () => (
    <ExpensesTableApplove
      expenses={expenses}
      page={page}
      size={size}
      setPage={setPage}
      setSize={setSize}
      handleEdit={handleEdit}
      handleDelete={handleDelete}
      filter={filter}
      handleApprove={handleApprove}
      handleSuccess={handleSuccess}
      handleBillPickup={handleBillPickup}
      handleDetail={handleDetail}
      handleOpenPay={handleOpenPay}
      handleAddMultiPayment={handleAddMultiPayment}
      selectedRows={selectedRows}
      setSelectedRows={setSelectedRows}
      handleReject={handleReject}
      handleReset={handleReset}
      handleOpenPrepareModal={handleOpenPrepareModal}
    />
  );

  const options = ['CREATE EXPENSE', 'PRINT REPORT', 'EXPORT TO EXCEL'];

  const renderFiltersAndActions = () => (
    <Box sx={{ mb: 3 }}>
      <Card sx={{ borderRadius: 2, boxShadow: '0 2px 10px rgba(0,0,0,0.05)' }}>
        <Box sx={{ p: { xs: 1, sm: 2 } }}>
          <Stack
            direction={{ xs: 'column', sm: 'row' }}
            spacing={2}
            alignItems={{ xs: 'stretch', sm: 'center' }}
            justifyContent="space-between"
          >
            <Box sx={{ flex: 1, width: '100%' }}>
              <FilterFinanceExpenses
                project={projects}
                setFindProject={setFindProject}
                setSearch={setSearch}
                dateStart={dateStart}
                setDateStart={setDateStart}
              />
            </Box>

            {/* Desktop Actions */}
            <Box
              sx={{
                display: { xs: 'none', md: 'flex' },
                gap: 1,
                flexShrink: 0,
                alignItems: 'center',
              }}
            >
              <Tooltip title="เพิ่มรายการใหม่">
                <Button
                  variant="contained"
                  color="primary"
                  startIcon={<AddIcon />}
                  onClick={handleOpen}
                  sx={{
                    borderRadius: 2,
                    minWidth: { xs: '100%', sm: 'auto' },
                  }}
                >
                  สร้างรายการใหม่
                </Button>
              </Tooltip>

              <Tooltip title="พิมพ์รายงาน">
                <Button
                  variant="outlined"
                  color="primary"
                  startIcon={<PrintIcon />}
                  onClick={handlePrint}
                  sx={{
                    borderRadius: 2,
                    minWidth: { xs: '100%', sm: 'auto' },
                  }}
                >
                  พิมพ์
                </Button>
              </Tooltip>

              <Tooltip title="ส่งออกเป็น Excel">
                <Button
                  variant="outlined"
                  color="success"
                  startIcon={<GetAppIcon />}
                  onClick={handleExport}
                  sx={{
                    borderRadius: 2,
                    minWidth: { xs: '100%', sm: 'auto' },
                  }}
                >
                  Excel
                </Button>
              </Tooltip>
            </Box>

            {/* Mobile Actions */}
            <Box sx={{ display: { xs: 'flex', md: 'none' }, width: '100%' }}>
              <Stack direction="row" spacing={1} width="100%">
                <Button
                  variant="contained"
                  color="primary"
                  startIcon={<AddIcon />}
                  onClick={handleOpen}
                  sx={{ borderRadius: 2, flex: 1 }}
                >
                  สร้าง
                </Button>
                <Button
                  variant="outlined"
                  color="primary"
                  startIcon={<PrintIcon />}
                  onClick={handlePrint}
                  sx={{ borderRadius: 2, flex: 1 }}
                >
                  พิมพ์
                </Button>
                <Button
                  variant="outlined"
                  color="success"
                  startIcon={<GetAppIcon />}
                  onClick={handleExport}
                  sx={{ borderRadius: 2, flex: 1 }}
                >
                  Excel
                </Button>
              </Stack>
            </Box>
          </Stack>
        </Box>
      </Card>
    </Box>
  );

  const renderTitle = () => (
    <Box sx={{ mb: 2 }}>
      <ViewTitle title={title} subtitle={subtitle} />
    </Box>
  );

  const renderCustomerModal = () => (
    <Modal
      open={openCustomerModal}
      onClose={handleCloseCustomerModal}
      closeAfterTransition
      BackdropComponent={Backdrop}
      BackdropProps={{ timeout: 300 }}
    >
      <Fade in={openCustomerModal}>
        <Box
          sx={{
            position: 'absolute',
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            width: { xs: '95%', sm: '80%', md: 700 },
            maxHeight: '90vh',
            bgcolor: 'background.paper',
            borderRadius: 2,
            boxShadow: 24,
            p: 0,
            overflow: 'hidden',
          }}
        >
          <Box
            sx={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              bgcolor: 'primary.main',
              color: 'primary.contrastText',
              p: 2,
            }}
          >
            <Box sx={{ display: 'flex', alignItems: 'center' }}>
              <PersonIcon sx={{ mr: 1 }} />
              <Typography variant="h6">เพิ่มลูกค้าใหม่</Typography>
            </Box>
            <IconButton
              size="small"
              onClick={handleCloseCustomerModal}
              sx={{ color: 'white' }}
            >
              <CloseIcon />
            </IconButton>
          </Box>

          <Box sx={{ p: 3, maxHeight: 'calc(90vh - 64px)', overflowY: 'auto' }}>
            <form onSubmit={handleCustomerSubmit(onSubmitCustomer)}>
              <CustomerForm
                Controller={Controller}
                control={customerControl}
                errors={customerErrors}
                customerType={customerType}
                bank={bank}
                setBank={setBank}
              />

              <Box
                sx={{
                  display: 'flex',
                  justifyContent: 'flex-end',
                  mt: 3,
                  gap: 1,
                }}
              >
                <Button
                  variant="outlined"
                  onClick={handleCloseCustomerModal}
                  startIcon={<CloseIcon />}
                >
                  ยกเลิก
                </Button>
                <Button
                  variant="contained"
                  type="submit"
                  startIcon={<CheckCircleIcon />}
                >
                  บันทึกข้อมูล
                </Button>
              </Box>
            </form>
          </Box>
        </Box>
      </Fade>
    </Modal>
  );

  return (
    <div>
      {renderTitle()}
      {renderFiltersAndActions()}
      {renderSummary()}
      {renderTable()}
      {renderModal()}
      {renderModalAddPayment()}
      {renderCustomerModal()}
      {renderPrepareModal()}
    </div>
  );
}

export default ExpensesList;
